    "lessons.lesson.abg-basics": "Fundamentos de Interpretación de ABG",
    "lessons.lesson.abg-interpretation-rn": "Interpretación de ABG y Equilibrio Ácido-Base",
    "lessons.lesson.abg-sampling-np": "Muestreo de ABG e Interpretación",
    "lessons.lesson.abnormal-uterine-bleeding": "Sangrado Uterino Anormal",
    "lessons.lesson.abnormal-uterine-bleeding-rpn": "Sangrado Uterino Anormal",
    "lessons.lesson.acetaminophen-od-np": "Sobredosis de Acetaminofén: Protocolo NAC y Rumack-Matthew",
